import java.util.Arrays;
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int n = scanner.nextInt();
        int[] arr = new int[n];
        for (int i = 0; i < n; i++) {
            arr[i] = scanner.nextInt();
        }
        Arrays.sort(arr);
        int median = arr[n / 2];
        int moves = 0;
        for (int i = 0; i < n; i++) {
            moves += Math.abs(arr[i] - median);
        }
        System.out.println(moves);
    }
}

code.JavaScript:
const readline = require('readline').createInterface({
    input: process.stdin,
    output: process.stdout
});
let i = 0;
let n;
let arr = [];
readline.on('line', line => {
    if (i === 0) {
        n = parseInt(line);
    } else {
        arr.push(parseInt(line));
    }
    i++;
    if (i > n) {
        arr.sort((a, b) => a - b);
        let median = arr[Math.floor(n / 2)];
        let moves = 0;
        for (let j = 0; j < n; j++) {
            moves += Math.abs(arr[j] - median);
        }
        console.log(moves);
        readline.close();
    }
});
